parameters.jsCode:
const b = $input.first().json.body || $input.first().json;
if (!b.client_id || !b.campaign_theme) throw new Error('client_id and campaign_theme required');
return [{ json: {
  task_id: `content_${Date.now()}_${Math.random().toString(36).slice(2,8)}`,
  client_id: b.client_id,
  campaign_theme: b.campaign_theme,
  channels: b.channels || ['blog','email','meta_ads','linkedin','instagram','tiktok'],
  tone: b.tone || null,
  duration_days: b.duration_days || 30,
  kpi: b.kpi || 'leads',
  deliverables: b.deliverables || { blogs: 4, emails: 6, meta_ads: 10, social_posts: 20, images: 20, videos: 4 },
  started_at: new Date().toISOString()
} }];

parameters.jsonBody:
={
  "client_id": "{{ $json.client_id }}",
  "query": "Brand voice, ICP, positioning, unique value props, recent winners for theme: {{ $json.campaign_theme }}",
  "k": 25
}

={
  "agent": "campaign_brief",
  "model": "claude-sonnet-4-6",
  "task": "Build master campaign brief for theme '{{ $node['Validate Brief'].json.campaign_theme }}' (client {{ $node['Validate Brief'].json.client_id }}, {{ $node['Validate Brief'].json.duration_days }}d, KPI {{ $node['Validate Brief'].json.kpi }}). Deliver: narrative spine, message matrix per channel, funnel mapping TOFU/MOFU/BOFU, audience segments, hero CTA, content calendar skeleton week-by-week. Use brand voice from context.",
  "client_id": "{{ $node['Validate Brief'].json.client_id }}",
  "extra": { "brief": {{ JSON.stringify($node['Validate Brief'].json) }}, "brain": {{ JSON.stringify($json) }} }
}

={
  "agent": "content_creator",
  "model": "claude-sonnet-4-6",
  "task": "Produce {{ $node['Validate Brief'].json.deliverables.blogs }} SEO-optimized blog posts (1500-2200 words each) for theme '{{ $node['Validate Brief'].json.campaign_theme }}'. Each with: H1, meta description, H2/H3 outline, full body, internal links, FAQ schema block, target keyword + 3 LSI, reading level 8-9. Also output {{ $node['Validate Brief'].json.deliverables.social_posts }} social posts (LinkedIn long-form 1200c, Instagram caption 150c, TikTok hook 80c, X thread 6 tweets).",
  "client_id": "{{ $node['Validate Brief'].json.client_id }}",
  "extra": { "brief": {{ JSON.stringify($node['brief-agent'].json) }} }
}

={
  "agent": "copywriter",
  "model": "claude-sonnet-4-6",
  "task": "Write {{ $node['Validate Brief'].json.deliverables.meta_ads }} Meta Ads sets for theme '{{ $node['Validate Brief'].json.campaign_theme }}'. Each set = 3 headlines (30c) + 5 primary texts (125c) + 2 descriptions (27c) + CTA + target angle (pain/desire/proof/novelty/authority). Apply direct-response principles (Halbert/Sugarman). Output also 8 Google RSA (15 headlines / 4 descriptions).",
  "client_id": "{{ $node['Validate Brief'].json.client_id }}",
  "extra": { "brief": {{ JSON.stringify($node['brief-agent'].json) }} }
}

={
  "agent": "email_marketer",
  "model": "claude-sonnet-4-6",
  "task": "Design {{ $node['Validate Brief'].json.deliverables.emails }}-email nurture + broadcast series for theme '{{ $node['Validate Brief'].json.campaign_theme }}'. For each email: subject A/B (40c + 50c), preheader (90c), full MJML-ready HTML body, plain-text fallback, send time, segment, goal. Include 1 re-engagement and 1 cart/interest recovery if applicable.",
  "client_id": "{{ $node['Validate Brief'].json.client_id }}",
  "extra": { "brief": {{ JSON.stringify($node['brief-agent'].json) }} }
}

={
  "agent": "media_buyer",
  "model": "claude-sonnet-4-6",
  "task": "Build media plan across Meta, Google, LinkedIn, TikTok for theme '{{ $node['Validate Brief'].json.campaign_theme }}'. Output: channel-by-channel budget split (% and $), audience definitions (saved/custom/lookalike), bid strategy, placements, flight schedule, expected CPM/CPC/CPL ranges with sourcing, kill-switch rules, scale-up rules.",
  "client_id": "{{ $node['Validate Brief'].json.client_id }}",
  "extra": { "brief": {{ JSON.stringify($node['brief-agent'].json) }} }
}

={
  "agent": "brand_strategist",
  "model": "claude-opus-4-6",
  "task": "Review outputs from Content Creator, Copywriter, Email Marketer, and Media Buyer for brand alignment. Enforce voice consistency, positioning fidelity, and narrative coherence. Return: approval status per asset, surgical edits where misaligned, and a 'north-star' one-pager summarizing campaign identity.",
  "client_id": "{{ $node['Validate Brief'].json.client_id }}",
  "extra": { "creator": {{ JSON.stringify($node['creator'].json) }}, "copy": {{ JSON.stringify($node['copy'].json) }}, "email": {{ JSON.stringify($node['email'].json) }}, "media": {{ JSON.stringify($node['media'].json) }} }
}

={
  "prompt": "{{ $node['brief-agent'].json.response || $node['brief-agent'].json.output || '' }} — hero image for campaign {{ $node['Validate Brief'].json.campaign_theme }}, brand aligned, ultra-realistic, 16:9",
  "aspect_ratio": "16x9",
  "num_images": {{ $node['Validate Brief'].json.deliverables.images }},
  "style_type": "AUTO"
}

={
  "agent": "orchestrator",
  "model": "claude-opus-4-6",
  "task": "Assemble final content package and {{ $node['Validate Brief'].json.duration_days }}-day publishing calendar. Produce: day-by-day schedule with asset IDs, channel sequencing (awareness → consideration → conversion), cross-channel retargeting plan, measurement plan (UTMs, GA4 events, pixel events), and QA checklist.",
  "client_id": "{{ $node['Validate Brief'].json.client_id }}",
  "extra": { "merged": {{ JSON.stringify($json) }} }
}
